mapper.select:
SELECT l.log_id, l.job_name, l.trigger_type, l.run_time, l.total_count, l.success_count, l.fail_count, l.status, l.error_message, l.duration_ms, l.operator_id, u.real_name AS operator_name, l.created_at FROM fx_scheduled_job_log l LEFT JOIN fx_user u ON u.user_id = l.operator_id
AND l.job_name = #{jobName}
ORDER BY l.run_time DESC LIMIT #{offset}, #{pageSize}

SELECT COUNT(1)
FROM fx_scheduled_job_log


        AND job_name = #{jobName}
